<?php require_once __DIR__ . '/../includes/admin.php'; admin_required(); if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf($_POST['csrf']??null);$id=filter_input(INPUT_POST,'id',FILTER_VALIDATE_INT);$status=$_POST['status']??'';if($id&&in_array($status,['New','Contacted','Closed'],true))db()->prepare('UPDATE enquiries SET status=? WHERE id=?')->execute([$status,$id]);redirect('admin/enquiries.php');}$rows=db()->query('SELECT * FROM enquiries ORDER BY date DESC')->fetchAll();admin_head('Enquiries'); ?><h1>Site Visit Enquiries</h1><div class="card"><table><tr><th>Name & contact</th><th class="hide-mobile">Message</th><th>Date</th><th>Status</th></tr><?php foreach($rows as $row):?><tr><td><b><?=e($row['name'])?></b><br><a href="tel:<?=e($row['phone'])?>"><?=e($row['phone'])?></a><br><?=e($row['email'])?></td><td class="hide-mobile"><?=nl2br(e($row['message']))?></td><td><?=e($row['date'])?></td><td><form method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$row['id']?>"><select name="status" onchange="this.form.submit()"><?php foreach(['New','Contacted','Closed'] as $status):?><option <?=$row['status']===$status?'selected':''?>><?=$status?></option><?php endforeach?></select></form></td></tr><?php endforeach?></table></div><?php admin_foot(); ?>
